                    fontSize: '14px',
                    arrowheadColor: computedStyles.getPropertyValue('--highlight-color').trim(),
                };

                mermaid.initialize({ 
                    startOnLoad: true,
                    theme: 'base',
                    themeVariables: mermaidThemeVariables
                });
            } else {
                console.error('Mermaid library not loaded. Chart will not be rendered.');
