                    modalTitle.textContent = data.title;
                    modalContent.innerHTML = data.content;
                    modalOverlay.classList.add('visible');
                }
            });
        });

        const closeModal = () => {
             modalOverlay.classList.remove('visible');
        };

        modalCloseBtn.addEventListener('click', closeModal);
        modalOverlay.addEventListener('click', (e) => {
            if (e.target === modalOverlay) {
                closeModal();
            }
        });

        // --- Download Functionality ---
        const downloadJSONBtn = document.getElementById('download-json');
        const downloadYAMLBtn = document.getElementById('download-yaml');

        const downloadFile = (content, fileName, contentType) => {
            const a = document.createElement('a');
            const file = new Blob([content], {type: contentType});
            a.href = URL.createObjectURL(file);
            a.download = fileName;
            a.click();
            URL.revokeObjectURL(a.href);
        };

        downloadJSONBtn.addEventListener('click', () => {
            const jsonContent = JSON.stringify(productData, null, 2);
            downloadFile(jsonContent, 'product_data.json', 'application/json');
        });

        downloadYAMLBtn.addEventListener('click', () => {
            if (typeof jsyaml === 'undefined') {
                alert('YAML library not loaded. Cannot download YAML.');
                return;
            }
            try {
                const yamlContent = jsyaml.dump(productData);
                downloadFile(yamlContent, 'product_data.yaml', 'application/x-yaml');
            } catch (e) {
                console.error("Error converting to YAML:", e);
                alert("An error occurred while generating the YAML file.");
            }
        });

    });
